// Species silhouette icons (white-on-transparent PNG, converted from project reference images so
// they read cleanly against this app's dark UI). Keyed by the exact `species` string used in
// DATA. Every species value currently in DATA has an icon. SpeciesIcon below renders nothing for
// any future species without a matching entry here, rather than guessing or reusing an unrelated
// animal's silhouette.
// Species silhouette icons -- now plain relative image files (icons/*.png) instead of
// embedded base64, served alongside index.html and app.js. Every species value currently in
// DATA has an icon. SpeciesIcon below renders nothing for any future species without a
// matching entry here, rather than guessing or reusing an unrelated animal's silhouette.
// Species silhouette icons (white-on-transparent PNG, embedded as base64 so this file works
// standalone in Claude's artifact preview -- no sibling files needed). Every species value
// currently in DATA has an icon. SpeciesIcon below renders nothing for any future species
// without a matching entry here, rather than guessing or reusing an unrelated animal's silhouette.
const SPECIES_ICONS = {
  "Muskox": "data:image/png;base64,",
  "Bison": "data:image/png;base64,",
  "Dall Sheep": "data:image/png;base64,",
  "Caribou": "data:image/png;base64,",
  "Brown Bear": "data:image/png;base64,",
  "Antelope": "data:image/png;base64,",
  "Bear": "data:image/png;base64,",
  "Bighorn Sheep": "data:image/png;base64,",
  "Coues Deer": "data:image/png;base64,",
  "Desert Bighorn Sheep": "data:image/png;base64,",
  "Elk": "data:image/png;base64,",
  "Moose": "data:image/png;base64,",
  "Mountain Goat": "data:image/png;base64,",
  "Mule Deer": "data:image/png;base64,",
  "Deer": "data:image/png;base64,", // deliberate alias: generic "Deer" entries (e.g. MT, which mixes mule deer + whitetail under one species string) fall back to the mule deer icon rather than show nothing
  "Turkey": "data:image/png;base64,",
  "Whitetail Deer": "data:image/png;base64,",
};

function SpeciesIcon({ species, size = 72 }) {
  const src = SPECIES_ICONS[species];
  if (!src) return null;
  return (
    <img
      src={src}
      alt=""
      aria-hidden="true"
      style={{ width: size, height: "auto", maxHeight: size, opacity: 0.92, objectFit: "contain" }}
    />
  );
}

