// Per-state source attribution for ZONE_DATA tables. Demand-kind text describes where the
// pts100/transition/demandBelow figures actually came from — these differ meaningfully by
// state (different agencies, different applicant pools, different draw mechanics), so a single
// shared sentence would misattribute the data for every state but one.
// CPW's draw recap PDF excludes a different number of private-land-only/RFW/youth-only hunt
// codes per species (each species has its own total hunt-code count and program mix).
const CO_EXCLUDED_CODE_COUNTS = { "Mule Deer": 197, Elk: 232, Antelope: 73, Moose: 4, Bear: 5, "Bighorn Sheep": 1 };

// Species where a real per-hunt-code Success Rate has actually been recovered from CPW's
// published harvest-estimate reports (GMU-by-manner-of-take tables), as opposed to the species
// where CPW genuinely only publishes a statewide or herd-level number. Extend this list as more
// species get the same treatment — don't assume a species belongs here without verifying its
// harvest report actually breaks out by GMU first; several Colorado species (moose, bear, sheep,
// goat) do not, and never claim otherwise for those.
const CO_HARVEST_SOURCED_SPECIES = new Set(["Mule Deer", "Elk", "Antelope"]);

// Year of the most recent CPW harvest-estimates report actually used for each sourced species.
// Deer/Elk's archive lags CPW's site by ~1 year; Pronghorn's lags further (2022 is the most
// recent one archived anywhere accessible) — don't assume they're all the same vintage.
const CO_HARVEST_REPORT_YEAR = { "Mule Deer": 2024, Elk: 2024, Antelope: 2022 };

const WY_SPECIAL_PRICE = { Elk: "$1,950", Deer: "$1,200", Antelope: "$1,200" };
const WY_REGULAR_PRICE = { Elk: "$692", Deer: "$374", Antelope: "$326" };

const DEMAND_SOURCE_NOTE = {
  WY: (species) => {
    const reg = WY_REGULAR_PRICE[species];
    const special = WY_SPECIAL_PRICE[species];
    const elkNote = species === "Elk" ? ` (the reduced-price $288 Cow/Calf license has no Special-draw equivalent, so those hunt codes only show Regular)` : "";
    return `WGFD's official 2025 nonresident ${species.toLowerCase()} preference-point demand reports — both tiers Wyoming actually offers nonresidents. Use the Draw toggle above: Regular (${reg} + $15 application fee) is the standard path; Special (${special} + $15) is a pricier, separate application pool with its own real odds${elkNote}. "Pts for 100%" is the lowest point total that hit 100% success as a first choice in that tier's pool in 2025. Neither tier's 25% random (no-points) sub-pool is covered, and resident draws aren't covered at all — and odds shift year to year.`;
  },
  NE: () =>
    `Nebraska Game and Parks Commission's official nonresident deer permit drawing-odds data by management unit. "Pts for 100%" is the lowest preference-point total that hit 100% draw success — odds shift year to year. Success Rate is sourced from NGPC's 2025 Big Game Recommendations book (2024 season harvest by permit) — it's a statewide/all-residency rate, since Nebraska doesn't publish nonresident-specific harvest success separately.`,
  ND: () =>
    `North Dakota Game and Fish Department's official nonresident deer lottery drawing-odds data by unit. "Pts for 100%" is the lowest preference-point total that hit 100% draw success — odds shift year to year.`,
  CO: (species) => {
    const isWeighted = species === "Moose" || species === "Bighorn Sheep" || species === "Mountain Goat";
    const excluded = CO_EXCLUDED_CODE_COUNTS[species];
    const excludedText =
      !isWeighted && excluded != null
        ? `, plus ${excluded} private-land-only, Ranching-for-Wildlife, and youth-only hunt codes statewide`
        : "";
    const carryoverNote =
      species === "Moose" || species === "Bighorn Sheep"
        ? " Codes guaranteed as 2025 wildfire-displacement carryovers are excluded entirely, since they were never actually competitive."
        : "";
    const mechanic = isWeighted
      ? `${species} uses a different mechanic than deer/elk/antelope: preference points cap at 3, then a squared/weighted bonus-point lottery takes over — so "Pts for 100%" may read like "3 pref + 9 weighted" rather than a single number, and most hunt codes never reach 100% even at the highest weighted total anyone held that year.${species === "Moose" ? " Some rows combine multiple hunt codes (e.g. archery/muzzleloader/rifle) into one entry because CPW pools their applicants into a single ranked queue rather than running them as separate competitions;" : ""}${carryoverNote}`
      : `"Pts for 100%" is the lowest preference-point total that hit 100% draw success in 2026.`;
    const successText = CO_HARVEST_SOURCED_SPECIES.has(species)
      ? ` Success Rate is sourced separately from CPW's ${CO_HARVEST_REPORT_YEAR[species]} ${species} Harvest Estimates report (the most recent one publicly available; more recent editions exist but are hosted on a platform that blocks automated retrieval) and isn't filled for every hunt code; see the note below the table for why.`
      : ` Success Rate isn't shown: CPW's 2025 harvest survey results aren't published until March 2026, and even then are reported at the herd level, not per hunt code.`;
    return `Colorado Parks & Wildlife's official 2026 Primary ${species} Post Draw Report, nonresident adult applicants applying each hunt code as their first choice. ${mechanic} Excludes youth, landowner (LPP), and 2nd–4th-choice applicant pools${excludedText} — and odds shift year to year.${successText}`;
  },
  MT: (species) => {
    if (species === "Antelope") {
      return `MT FWP's official detailed bonus-point drawing-statistics reports, nonresident applicants only (resident and landowner-preference-pool rows excluded). Three separate license programs, two different report vintages: Archery (hunt codes 900-20, 399-20) is 2026 data from the "Antelope Archery Only" report; Regular (-20/-21 suffix) and B/Antlerless (-30/-31 suffix) are 2025 data from the separate "Antelope" and "Antelope B" reports — a full cycle older, so don't assume archery's numbers carry the same vintage. "Pts for 100%" is the lowest point total that hit 100% nonresident success in that report year; "Never reached 100%" rows show the actual ceiling reached at the highest point total anyone held. Quota is the real number of nonresident tags issued (summed across every point level), not a separately published cap. No harvest-success data exists in these reports at all — that's a different MT FWP publication not used here.`;
    }
    if (species === "Elk") {
      return `MT FWP's official 2026 detailed bonus-point drawing-statistics reports for the two limited-draw elk programs, nonresident applicants only (resident and landowner-preference-pool rows excluded). "Permit" is the limited-entry trophy/branch-antlered-bull tier — nonresidents must already hold a separate, much-higher-odds Combination License before applying for one, and that base Combination License draw isn't covered here. "B (Antlerless)" is the separate antlerless tag system. District labels include MT FWP's own free-text qualifiers ("ARCHERY ONLY", "(First Choice Only)", "(First and Only)") exactly as published — what those specifically restrict isn't explained in the report itself. "Pts for 100%" is the lowest point total that hit 100% nonresident success in 2026; several districts never reach it at any point total anyone held that year. Quota is the real number of nonresident tags issued (summed across every point level). No harvest-success data exists in these reports.`;
    }
    if (species === "Deer") {
      return `MT FWP's official 2026 detailed bonus-point drawing-statistics reports for the two limited-draw deer programs, nonresident applicants only (resident and landowner-preference-pool rows excluded). Same two-tier structure as elk: "Permit" requires a separate, much-higher-odds Deer Combination License first (not covered here); "B (Antlerless)" is the separate antlerless tag system. Area labels mix mule deer and whitetail permits under one MT FWP report — species/sex qualifiers ("MULE", "WT", "MULE OR WT", "EITHER SEX WT", "EITHER SEX WT CWD") are MT FWP's own wording, kept exactly as published. One row in the source B-license report (district 260-20 EITHER SEX WT, nonresident) was missing its point-level value in MT's own export and was excluded rather than guessed. Quota is the real number of nonresident tags issued. No harvest-success data exists in these reports.`;
    }
    return `MT FWP's official nonresident drawing-statistics data for ${species.toLowerCase()}.`;
  },
};
const REGULATION_SOURCE_NOTE = {
  WY: (species) =>
    `Wyoming Game & Fish Commission regulations (current hunt-area quota table) — exact resident/nonresident license splits and season dates per area. Point-by-point demand data wasn't available for ${species.toLowerCase()}; many areas issue zero nonresident tags regardless of points, which is itself the key fact for this species.`,
  CO: (species) =>
    `Colorado Parks & Wildlife's official 2026 Primary ${species} Post Draw Report. ${species} has no preference-point system at all — it's a pure random draw open equally to every applicant regardless of history, so there's no "points" data to show. This table is each unit's real quota and resident/nonresident split instead.`,
};

// Why some demand tables show "—" instead of a Success Rate — varies by state because the
// harvest-report sourcing situation genuinely differs (some states publish one, some don't,
// some publish one too coarse to map onto individual hunt codes).
const MISSING_SUCCESS_NOTE = {
  WY: `Success Rate is sourced from WGFD's 2025 Harvest Report by hunt area and license type. A few hunt codes didn't have a directly matching row in that report and show "—" rather than a guessed number.`,
  CO: (species) => {
    if (CO_HARVEST_SOURCED_SPECIES.has(species)) {
      const year = CO_HARVEST_REPORT_YEAR[species];
      if (species === "Antelope") {
        return `Success Rate is sourced from CPW's ${year} Pronghorn Harvest Estimates report (the most recent one archived anywhere accessible — pronghorn's archive lags further behind than deer/elk's). Unlike deer and elk, CPW's pronghorn report never splits hunters by sex for any manner of take — every table is buck+doe combined. A number is only filled when a unit happens to offer just one sex for that manner (so the combined figure is unambiguous); most units offer both a buck and a doe hunt code for the same manner, which is why coverage here is much lower than deer/elk and most rows show "—" rather than a guessed split.`;
      }
      const rifle1Note = species === "Elk" ? "1st/2nd/3rd/4th rifle" : "2nd/3rd/4th rifle";
      const eitherSexNote =
        species === "Elk"
          ? ` Elk additionally has a dedicated either-sex table by season, so E-type rifle hunt codes get a real number too — deer's report doesn't break either-sex out at all, so deer's either-sex codes stay "—".`
          : "";
      return `Success Rate is sourced from CPW's ${year} ${species} Harvest Estimates report (GMU-by-season-by-manner-of-take tables — the most recent publicly archived edition; more recent editions exist but are hosted on a platform that blocks automated retrieval). Filled wherever that report has a clean, unambiguous match: ${rifle1Note} and muzzleloader seasons split antlered/antlerless success directly; archery and early/late seasons only when a unit has exactly one hunt code in that category (the report doesn't break those out by sex).${eitherSexNote} Left as "—" rather than guessed wherever a unit's hunt codes split a season/manner the report only reports combined, or there's no either-sex breakout for that manner of take at all.`;
    }
    return `Success Rate isn't shown for Colorado ${species.toLowerCase()} — CPW's 2025 Big Game Harvest Survey results aren't published until March 2026, and even then are reported at the herd level, not broken out per hunt code. Showing "—" rather than a guessed number.`;
  },
  MT: () =>
    `Success Rate isn't shown for Montana — these are pure drawing-statistics reports (points, applicants, draw success) with no harvest data in them at all. MT FWP publishes harvest survey results separately, and that report hasn't been pulled into this dataset yet.`,
};

